import React, { useState } from 'react';
import { ThemeProvider } from './context/ThemeContext';
import LeagueSetupStep1 from './components/LeagueSetupStep1';

function AppContent() {
  const [step, setStep] = useState(1);
  const [leagueSettings, setLeagueSettings] = useState(null);

  const handleStep1Next = (settings) => {
    setLeagueSettings(settings);
    setStep(2);
  };

  return (
    <div className="app">
      {step === 1 && <LeagueSetupStep1 onNext={handleStep1Next} />}
      {step === 2 && (
        <div
          style={{
            color: 'var(--cream)',
            fontFamily: 'DM Sans, sans-serif',
            textAlign: 'center',
            marginTop: '4rem',
          }}
        >
          <h2>Step 2: Player Entry — Coming Soon</h2>
          <p style={{ marginTop: '1rem', color: 'var(--muted)' }}>
            Settings saved for: <strong>{leagueSettings?.leagueName}</strong>
          </p>
          <button
            onClick={() => setStep(1)}
            style={{
              marginTop: '1.5rem',
              background: 'none',
              border: '1px solid var(--lime)',
              color: 'var(--lime)',
              padding: '0.5rem 1.2rem',
              cursor: 'pointer',
              borderRadius: '2px',
              fontFamily: 'DM Sans, sans-serif',
            }}
          >
            ← Back
          </button>
        </div>
      )}
    </div>
  );
}

function App() {
  return (
    <ThemeProvider>
      <AppContent />
    </ThemeProvider>
  );
}

export default App;
